previous_inlet_open = controller->inlet_open;
 previous_heater_on = controller->heater_on;
 previous_state = controller->state;

 /* Update sensor freshness and check for timeout */
 bool has_temperature = false;
 bool has_level = false;
 bool timeout = false;

 switch (input.kind) {
 case CONTROLLER_INPUT_TEMPERATURE:
     controller->has_valid_temperature = true;
     controller->previous_temperature_c = controller->last_temperature_c;
     controller->last_temperature_c = input.temperature_c;
     controller->last_temperature_ms = input.now_ms;
     has_temperature = true;
     break;
 case CONTROLLER_INPUT_LEVEL:
     controller->has_valid_level = true;
     controller->last_level = input.level;
     controller->last_level_ms = input.now_ms;
     has_level = true;
     break;
 case CONTROLLER_INPUT_SENSOR_TIMEOUT:
 case CONTROLLER_INPUT_INVALID_TEMPERATURE:
 case CONTROLLER_INPUT_INVALID_LEVEL:
     controller->has_valid_temperature = false;
     controller->has_valid_level = false;
     timeout = true;
     break;
 case CONTROLLER_INPUT_NONE:
 default:
     /* No input - check for stale sensors */
     break;
 }

 /* Check for sensor timeout (more than 1000ms since last valid reading) */
 uint32_t now_ms = input.now_ms;
 if (!timeout && (controller->has_valid_temperature || controller->has_valid_level)) {
     if (controller->has_valid_temperature &&
         (now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
         controller->has_valid_temperature = false;
     }
     if (controller->has_valid_level &&
         (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
         controller->has_valid_level = false;
     }
 }

 /* Stay in safe state until both sensors are valid */
 has_temperature = has_temperature || controller->has_valid_temperature;
 has_level = has_level || controller->has_valid_level;

 if (!has_temperature || !has_level) {
     controller_set_safe_idle(controller);
 } else {
     /* Apply control policy */
     int level = controller->last_level;
     int temp = controller->last_temperature_c;
     bool inlet_open = false;
     bool heater_on = false;
     controller_state_t state = CONTROLLER_STATE_SAFE_IDLE;

     if (level < 60) {
         /* FILLING: inlet open, heater off */
         inlet_open = true;
         heater_on = false;
         state = CONTROLLER_STATE_FILLING;
     } else if (level > 75) {
         /* Level too high - close inlet */
         inlet_open = false;
         heater_on = false;
         /* Check if we can heat or need to hold */
         if (temp >= 45 && temp < 47) {
             state = CONTROLLER_STATE_HOLDING;
             heater_on = controller->heater_on; /* hold previous state */
         } else if (temp >= 47 && temp <= 48) {
             state = CONTROLLER_STATE_HEATING;
             heater_on = controller->heater_on; /* hold previous state */
         } else if (temp > 48) {
             state = CONTROLLER_STATE_SAFE_IDLE;
             heater_on = false;
         } else {
             /* temp < 45, can heat */
             state = CONTROLLER_STATE_HEATING;
             heater_on = true;
         }
     } else if (level >= 60 && level <= 75) {
         /* In working region */
         inlet_open = false;

         if (temp < 45) {
             /* Heat up */
             state = CONTROLLER_STATE_HEATING;
             heater_on = true;
         } else if (temp >= 45 && temp < 47) {
             /* Near band - hold previous safe heater state */
             state = CONTROLLER_STATE_HOLDING;
